const items = $input.all();

return items.filter((item) => {
  const normalizedTitle = (item.json.title || '').toLowerCase();
  const normalizedLink = (item.json.link || '').toLowerCase();

  const includeKeywords = [
    'tax',
    'guideline',
    'compliance',
    'reporting',
    'filing',
    'penalty',
    'enforcement',
    'transparency',
    'electronic invoicing',
    'e-invoicing',
    'policy',
    'law',
    'regulation',
    'reform',
    'withholding',
    'irs',
    'fbar',
    'vat'
  ];

  const excludeKeywords = [
    'advises',
    'advised',
    'featured in',
    'earns',
    'receives',
    'rankings',
    'award',
    'acquisition',
    'financing',
    'counsel to',
    'sale of'
  ];

  const matchesIncludeKeyword = includeKeywords.some((keyword) =>
    normalizedTitle.includes(keyword)
  );

  const matchesExcludeKeyword = excludeKeywords.some((keyword) =>
    normalizedTitle.includes(keyword)
  );

  const isInsightPublication = normalizedLink.includes('/insight/publications/');

  return isInsightPublication && matchesIncludeKeyword && !matchesExcludeKeyword;
});

const items = $input.all();

return items.map((item) => {
  const rawText = item.json.content?.parts?.[0]?.text || '';

  let parsed;

  try {
    parsed = JSON.parse(rawText);
  } catch (error) {
    parsed = {
      actionable: "No",
      reason: "Failed to parse Gemini JSON response",
      summary: rawText,
      priority: "Low",
      checklist: [],
      owner_team: "Monitor",
      due_timeline: "monitor"
    };
  }

  return {
    json: {
      ...item.json,
      ...parsed
    }
  };
});
